import { afterEach, describe, expect, it, vi } from "vitest";
import { fetchReplayStatus } from "./readReplayStatus.js";
describe("fetchReplayStatus", () => {
    afterEach(() => {
        vi.restoreAllMocks();
    });
    it("returns the current replay status plus mapped count", async () => {
        vi.spyOn(globalThis, "fetch").mockResolvedValueOnce({
            ok: true,
            json: async () => ({
                testRunId: "11111111-1111-4111-8111-111111111111",
                status: "pending",
                traceIds: {
                    "local-1": "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa",
                    "local-2": "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb",
                },
                traceCount: 3,
            }),
        });
        const result = await fetchReplayStatus({
            serviceUrl: "https://bitfab.test/",
            apiKey: "sk_test",
            testRunId: "11111111-1111-4111-8111-111111111111",
        });
        expect(globalThis.fetch).toHaveBeenCalledWith("https://bitfab.test/api/sdk/replay/status", expect.objectContaining({
            method: "POST",
            headers: expect.objectContaining({
                Authorization: "Bearer sk_test",
                "Content-Type": "application/json",
            }),
            body: JSON.stringify({
                testRunId: "11111111-1111-4111-8111-111111111111",
            }),
        }));
        expect(result).toEqual({
            status: "ok",
            testRunId: "11111111-1111-4111-8111-111111111111",
            testRunStatus: "pending",
            traceIds: {
                "local-1": "aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa",
                "local-2": "bbbbbbbb-bbbb-4bbb-8bbb-bbbbbbbbbbbb",
            },
            traceCount: 3,
            mappedCount: 2,
        });
    });
    it("returns a structured error for non-ok responses", async () => {
        vi.spyOn(globalThis, "fetch").mockResolvedValueOnce({
            ok: false,
            status: 400,
            json: async () => ({ error: "Test run not found" }),
        });
        await expect(fetchReplayStatus({
            serviceUrl: "https://bitfab.test",
            apiKey: "sk_test",
            testRunId: "11111111-1111-4111-8111-111111111111",
        })).resolves.toEqual({ status: "error", message: "Test run not found" });
    });
});
